const m="http://localhost:8000/api",u=document.getElementById("error-msg");function i(t){u.textContent=t,u.classList.remove("hidden")}function c(){u.classList.add("hidden")}async function v(t){try{const e=await t.json();return Array.isArray(e.detail)?e.detail[0]?.msg||"Request failed":e.detail||"Request failed"}catch{return"Request failed"}}function b(t){try{return new URL(t).hostname}catch{return t}}async function g(){c();const e=await(await fetch(`${m}/sources`)).json(),r=document.getElementById("sources-list");if(!e.length){r.innerHTML='<div class="alert bg-base-200 text-sm">No sources configured. Add one to get started.</div>';return}r.innerHTML=`<ul class="list bg-base-100 border border-base-300 rounded-box divide-y divide-base-200">
        ${e.map(n=>`
          <li class="list-row flex-wrap items-center gap-3 py-3">
            <div class="flex items-center gap-2 min-w-0">
              <span class="font-medium">${s(n.name)}</span>
              <span class="badge badge-sm badge-soft">${s(n.source_type)}</span>
            </div>
            <div class="list-col-grow flex items-center gap-1 min-w-0">
              <a href="${s(n.url)}" target="_blank" rel="noopener noreferrer" class="text-sm text-base-content/50 truncate hover:text-primary transition-colors" title="${s(n.url)}">${s(b(n.url))}</a>
              <button class="btn btn-square btn-ghost btn-xs shrink-0" data-action="copy" data-url="${s(n.url)}" aria-label="Copy URL">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>
              </button>
            </div>
            <div class="flex flex-wrap gap-1">
              ${(n.tags||[]).map(d=>`<span class="badge badge-sm badge-soft badge-primary">${s(d)}</span>`).join("")}
            </div>
            <span class="badge badge-sm badge-ghost">${n.priority}</span>
            <div class="flex gap-1">
              <a href="/sources/edit?id=${n.id}" class="btn btn-square btn-ghost btn-sm" aria-label="Edit source">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/></svg>
              </a>
              <button class="btn btn-square btn-ghost btn-sm text-error" data-action="delete" data-id="${n.id}" aria-label="Delete source">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
              </button>
            </div>
          </li>`).join("")}
      </ul>`}function s(t){if(!t)return"";const e=document.createElement("div");return e.appendChild(document.createTextNode(t)),e.innerHTML}function f(){document.getElementById("form-title").textContent="Add Source",document.getElementById("modal-save").textContent="Save",document.getElementById("src-name").value="",document.getElementById("src-type").value="rss",document.getElementById("src-url").value="",document.getElementById("src-priority").value="2",document.getElementById("src-tags").value="",document.getElementById("form-modal").showModal()}document.getElementById("sources-list").addEventListener("click",async t=>{const e=t.target.closest("[data-action]");if(e){if(c(),e.dataset.action==="delete"){const r=e.dataset.id;if(!(await fetch(`${m}/sources/${r}`,{method:"DELETE"})).ok){i("Failed to delete source");return}g()}else if(e.dataset.action==="copy")try{await navigator.clipboard.writeText(e.dataset.url);const r=e.querySelector("svg"),n=e.innerHTML;e.innerHTML='<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>',e.classList.add("text-success"),setTimeout(()=>{e.innerHTML=n,e.classList.remove("text-success")},1500)}catch{i("Failed to copy URL")}}});document.getElementById("btn-add").addEventListener("click",()=>{c(),f()});document.getElementById("modal-cancel").addEventListener("click",()=>{document.getElementById("form-modal").close()});document.getElementById("modal-save").addEventListener("click",async()=>{const t=document.getElementById("src-name").value.trim(),e=document.getElementById("src-type").value,r=document.getElementById("src-url").value.trim(),n=parseInt(document.getElementById("src-priority").value),d=document.getElementById("src-tags").value.trim();if(!t||!r){i("Name and URL are required.");return}const a=document.getElementById("modal-save");a.disabled=!0;const y=a.textContent;a.textContent="Saving...",c();try{const l=d?d.split(",").map(o=>o.trim()):[],h=new URLSearchParams({name:t,source_type:e,url:r,priority:String(n)});l.forEach(o=>h.append("tags",o));const p=await fetch(`${m}/sources?${h}`,{method:"POST"});if(!p.ok)throw new Error(await v(p));document.getElementById("form-modal").close(),["src-name","src-url","src-tags"].forEach(o=>document.getElementById(o).value=""),g()}catch(l){i("Error: "+l.message)}finally{a.disabled=!1,a.textContent=y}});g();
